class Solution {
public:
    int rearrangeCharacters(string s, string target) {
        unordered_map<char, int> s_count, target_count;
        for (char c : s) s_count[c]++;
        for (char c : target) target_count[c]++;

        int ans = INT_MAX;
        for (auto& [c, count] : target_count) {
            if (s_count.find(c) == s_count.end()) return 0;
            ans = min(ans, s_count[c] / count);
        }
        return ans;
    }
};
